declare const GetAtomsDocument = "\n    query GetAtoms($limit: Int, $offset: Int, $orderBy: [atoms_order_by!], $where: atoms_bool_exp) {\n  total: atoms_aggregate(where: $where) {\n    aggregate {\n      count\n    }\n  }\n  atoms(limit: $limit, offset: $offset, order_by: $orderBy, where: $where) {\n    ...AtomMetadata\n    ...AtomTxn\n    ...AtomVaultDetails\n    ...AtomTriple\n    creator {\n      ...AccountMetadata\n    }\n  }\n}\n    \n    fragment AtomMetadata on atoms {\n  term_id\n  data\n  image\n  label\n  emoji\n  type\n  wallet_id\n  creator {\n    id\n    label\n    image\n  }\n  ...AtomValue\n}\n    \n\n    fragment AtomValue on atoms {\n  value {\n    person {\n      name\n      image\n      description\n      url\n    }\n    thing {\n      name\n      image\n      description\n      url\n    }\n    organization {\n      name\n      image\n      description\n      url\n    }\n    account {\n      id\n      label\n      image\n    }\n  }\n}\n    \n\n    fragment AtomTxn on atoms {\n  block_number\n  created_at\n  transaction_hash\n  creator_id\n}\n    \n\n    fragment AtomVaultDetails on atoms {\n  term_id\n  wallet_id\n  term {\n    vaults(where: {curve_id: {_eq: \"1\"}}) {\n      position_count\n      total_shares\n      current_share_price\n      positions_aggregate {\n        aggregate {\n          count\n          sum {\n            shares\n          }\n        }\n      }\n      positions {\n        id\n        account {\n          label\n          id\n        }\n        shares\n      }\n    }\n  }\n}\n    \n\n    fragment AtomTriple on atoms {\n  as_subject_triples {\n    term_id\n    object {\n      data\n      term_id\n      image\n      label\n      emoji\n      type\n      creator {\n        ...AccountMetadata\n      }\n    }\n    predicate {\n      data\n      term_id\n      image\n      label\n      emoji\n      type\n      creator {\n        ...AccountMetadata\n      }\n    }\n  }\n  as_predicate_triples {\n    term_id\n    subject {\n      data\n      term_id\n      image\n      label\n      emoji\n      type\n      creator {\n        ...AccountMetadata\n      }\n    }\n    object {\n      data\n      term_id\n      image\n      label\n      emoji\n      type\n      creator {\n        ...AccountMetadata\n      }\n    }\n  }\n  as_object_triples {\n    term_id\n    subject {\n      data\n      term_id\n      image\n      label\n      emoji\n      type\n      creator {\n        ...AccountMetadata\n      }\n    }\n    predicate {\n      data\n      term_id\n      image\n      label\n      emoji\n      type\n      creator {\n        ...AccountMetadata\n      }\n    }\n  }\n}\n    \n\n    fragment AccountMetadata on accounts {\n  label\n  image\n  id\n  atom_id\n  type\n}\n    ";
