declare const GetEventsDocument = "\n    query GetEvents($limit: Int, $offset: Int, $orderBy: [events_order_by!], $where: events_bool_exp, $addresses: [String!]) {\n  total: events_aggregate(where: $where) {\n    aggregate {\n      count\n    }\n  }\n  events(limit: $limit, offset: $offset, order_by: $orderBy, where: $where) {\n    id\n    block_number\n    created_at\n    type\n    transaction_hash\n    atom_id\n    triple_id\n    deposit_id\n    redemption_id\n    atom {\n      ...AtomMetadata\n      term {\n        vaults(where: {curve_id: {_eq: \"1\"}}) {\n          total_shares\n          position_count\n          positions(where: {account: {id: {_in: $addresses}}}) {\n            account_id\n            shares\n            account {\n              id\n              label\n              image\n            }\n          }\n        }\n      }\n    }\n    triple {\n      term_id\n      creator {\n        ...AccountMetadata\n      }\n      subject {\n        data\n        term_id\n        image\n        label\n        emoji\n        type\n        ...AtomValue\n        creator {\n          ...AccountMetadata\n        }\n      }\n      predicate {\n        data\n        term_id\n        image\n        label\n        emoji\n        type\n        ...AtomValue\n        creator {\n          ...AccountMetadata\n        }\n      }\n      object {\n        data\n        term_id\n        image\n        label\n        emoji\n        type\n        ...AtomValue\n        creator {\n          ...AccountMetadata\n        }\n      }\n      term {\n        vaults(where: {curve_id: {_eq: \"1\"}}) {\n          total_shares\n          position_count\n          positions(where: {account: {id: {_in: $addresses}}}) {\n            account_id\n            shares\n            account {\n              id\n              label\n              image\n            }\n          }\n        }\n      }\n      counter_term {\n        vaults(where: {curve_id: {_eq: \"1\"}}) {\n          total_shares\n          position_count\n          positions(where: {account: {id: {_in: $addresses}}}) {\n            account_id\n            shares\n            account {\n              id\n              label\n              image\n            }\n          }\n        }\n      }\n    }\n    deposit {\n      sender_id\n      sender {\n        id\n      }\n      shares_for_receiver\n      sender_assets_after_total_fees\n      vault {\n        total_shares\n        position_count\n        positions(where: {account: {id: {_in: $addresses}}}) {\n          account_id\n          shares\n          account {\n            id\n            label\n            image\n          }\n        }\n      }\n    }\n    redemption {\n      sender_id\n      sender {\n        id\n      }\n    }\n  }\n}\n    \n    fragment AtomMetadata on atoms {\n  term_id\n  data\n  image\n  label\n  emoji\n  type\n  wallet_id\n  creator {\n    id\n    label\n    image\n  }\n  ...AtomValue\n}\n    \n\n    fragment AtomValue on atoms {\n  value {\n    person {\n      name\n      image\n      description\n      url\n    }\n    thing {\n      name\n      image\n      description\n      url\n    }\n    organization {\n      name\n      image\n      description\n      url\n    }\n    account {\n      id\n      label\n      image\n    }\n  }\n}\n    \n\n    fragment AccountMetadata on accounts {\n  label\n  image\n  id\n  atom_id\n  type\n}\n    ";
