declare const GetEventsWithAggregatesDocument = "\n    query GetEventsWithAggregates($limit: Int, $offset: Int, $orderBy: [events_order_by!], $where: events_bool_exp, $addresses: [String!]) {\n  events_aggregate(\n    where: $where\n    limit: $limit\n    offset: $offset\n    order_by: $orderBy\n  ) {\n    aggregate {\n      count\n      max {\n        created_at\n        block_number\n      }\n      min {\n        created_at\n        block_number\n      }\n    }\n    nodes {\n      ...EventDetails\n    }\n  }\n}\n    \n    fragment EventDetails on events {\n  block_number\n  created_at\n  type\n  transaction_hash\n  atom_id\n  triple_id\n  deposit_id\n  redemption_id\n  ...DepositEventFragment\n  ...RedemptionEventFragment\n  atom {\n    ...AtomMetadata\n    term {\n      vaults(where: {curve_id: {_eq: \"1\"}}) {\n        total_shares\n        position_count\n        positions {\n          account_id\n          shares\n          account {\n            id\n            label\n            image\n          }\n        }\n      }\n    }\n  }\n  triple {\n    ...TripleMetadata\n    term {\n      vaults(where: {curve_id: {_eq: \"1\"}}) {\n        total_shares\n        position_count\n        positions {\n          account_id\n          shares\n          account {\n            id\n            label\n            image\n          }\n        }\n      }\n    }\n    counter_term {\n      vaults(where: {curve_id: {_eq: \"1\"}}) {\n        total_shares\n        position_count\n        positions {\n          account_id\n          shares\n          account {\n            id\n            label\n            image\n          }\n        }\n      }\n    }\n  }\n}\n    \n\n    fragment DepositEventFragment on events {\n  deposit {\n    term_id\n    curve_id\n    sender_assets_after_total_fees\n    shares_for_receiver\n    receiver {\n      id\n    }\n    sender {\n      id\n    }\n  }\n}\n    \n\n    fragment RedemptionEventFragment on events {\n  redemption {\n    term_id\n    curve_id\n    receiver_id\n    shares_redeemed_by_sender\n    assets_for_receiver\n  }\n}\n    \n\n    fragment AtomMetadata on atoms {\n  term_id\n  data\n  image\n  label\n  emoji\n  type\n  wallet_id\n  creator {\n    id\n    label\n    image\n  }\n  ...AtomValue\n}\n    \n\n    fragment AtomValue on atoms {\n  value {\n    person {\n      name\n      image\n      description\n      url\n    }\n    thing {\n      name\n      image\n      description\n      url\n    }\n    organization {\n      name\n      image\n      description\n      url\n    }\n    account {\n      id\n      label\n      image\n    }\n  }\n}\n    \n\n    fragment TripleMetadata on triples {\n  term_id\n  subject_id\n  predicate_id\n  object_id\n  subject {\n    data\n    term_id\n    image\n    label\n    emoji\n    type\n    ...AtomValue\n    creator {\n      ...AccountMetadata\n    }\n  }\n  predicate {\n    data\n    term_id\n    image\n    label\n    emoji\n    type\n    ...AtomValue\n    creator {\n      ...AccountMetadata\n    }\n  }\n  object {\n    data\n    term_id\n    image\n    label\n    emoji\n    type\n    ...AtomValue\n    creator {\n      ...AccountMetadata\n    }\n  }\n  term {\n    vaults(where: {curve_id: {_eq: \"1\"}}) {\n      total_shares\n      current_share_price\n      allPositions: positions_aggregate {\n        ...PositionAggregateFields\n      }\n      positions {\n        ...PositionFields\n      }\n    }\n  }\n  counter_term {\n    vaults(where: {curve_id: {_eq: \"1\"}}) {\n      total_shares\n      current_share_price\n      allPositions: positions_aggregate {\n        ...PositionAggregateFields\n      }\n      positions {\n        ...PositionFields\n      }\n    }\n  }\n}\n    \n\n    fragment AccountMetadata on accounts {\n  label\n  image\n  id\n  atom_id\n  type\n}\n    \n\n    fragment PositionAggregateFields on positions_aggregate {\n  aggregate {\n    count\n    sum {\n      shares\n    }\n  }\n}\n    \n\n    fragment PositionFields on positions {\n  account {\n    id\n    label\n  }\n  shares\n  vault {\n    term_id\n    total_shares\n    current_share_price\n  }\n}\n    ";
