declare const GetListItemsDocument = "\n    query GetListItems($predicateId: numeric, $objectId: numeric) {\n  triples_aggregate(\n    where: {predicate_id: {_eq: predicateId}, object_id: {_eq: $objectId}}\n    order_by: [{term: {positions_aggregate: {count: desc}}, counter_term: {positions_aggregate: {count: desc}}}]\n  ) {\n    aggregate {\n      count\n    }\n    nodes {\n      ...TripleVaultDetails\n    }\n  }\n}\n    \n    fragment TripleVaultDetails on triples {\n  term_id\n  counter_term_id\n  term {\n    vaults(where: {curve_id: {_eq: \"1\"}}) {\n      positions {\n        ...PositionDetails\n      }\n    }\n  }\n  counter_term {\n    vaults(where: {curve_id: {_eq: \"1\"}}) {\n      positions {\n        ...PositionDetails\n      }\n    }\n  }\n}\n    \n\n    fragment PositionDetails on positions {\n  id\n  account {\n    id\n    label\n    image\n  }\n  vault {\n    term_id\n    term {\n      atom {\n        term_id\n        label\n        image\n      }\n      triple {\n        term_id\n        term {\n          vaults(where: {curve_id: {_eq: \"1\"}}) {\n            term_id\n            position_count\n            positions_aggregate {\n              aggregate {\n                sum {\n                  shares\n                }\n              }\n            }\n          }\n        }\n        counter_term {\n          vaults(where: {curve_id: {_eq: \"1\"}}) {\n            term_id\n            position_count\n            positions_aggregate {\n              aggregate {\n                sum {\n                  shares\n                }\n              }\n            }\n          }\n        }\n        subject {\n          data\n          term_id\n          label\n          image\n          emoji\n          type\n          ...AtomValue\n          creator {\n            ...AccountMetadata\n          }\n        }\n        predicate {\n          data\n          term_id\n          label\n          image\n          emoji\n          type\n          ...AtomValue\n          creator {\n            ...AccountMetadata\n          }\n        }\n        object {\n          data\n          term_id\n          label\n          image\n          emoji\n          type\n          ...AtomValue\n          creator {\n            ...AccountMetadata\n          }\n        }\n      }\n    }\n  }\n  shares\n  term_id\n  curve_id\n}\n    \n\n    fragment AtomValue on atoms {\n  value {\n    person {\n      name\n      image\n      description\n      url\n    }\n    thing {\n      name\n      image\n      description\n      url\n    }\n    organization {\n      name\n      image\n      description\n      url\n    }\n    account {\n      id\n      label\n      image\n    }\n  }\n}\n    \n\n    fragment AccountMetadata on accounts {\n  label\n  image\n  id\n  atom_id\n  type\n}\n    ";
